#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
int n,m,k,fa[N],sz[N];
vector<pii> vec[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
int FF(int u){return (fa[u]==u?u:FF(fa[u]));}
void Add_edge(int u,int l,int r,int L,int R,int x,int y){
    if(r<L||R<l)return;
    if(L<=l&&r<=R){vec[u].pb({x,y});return;}
    int mid=(l+r)>>1;
    Add_edge(ls(u),l,mid,L,R,x,y);
    Add_edge(rs(u),mid+1,r,L,R,x,y);
    return;
}
void calc(stack<pair<int&,int>>&st,int x,int y){
    int Fx=FF(x),Fy=FF(y);
    if(sz[Fx]>sz[Fy])swap(x,y),swap(Fx,Fy);
    st.push({fa[Fx],fa[Fx]}),fa[Fx]=Fy;
    if(sz[Fx]==sz[Fy])
        st.push({sz[Fy],sz[Fy]}),sz[Fy]++;
    return;
}
void Sol(int u,int l,int r){
    stack<pair<int&,int>> st;
    while(!st.empty())st.pop();
    bool outp=0;
    for(auto [x,y]:vec[u]){
        if(FF(x)==FF(y)){
            for(int i=l;i<=r;i++)cout<<"No\n";
            outp=1;break;
        }calc(st,x+n,y),calc(st,x,y+n);
    }if(!outp){
        if(l==r)cout<<"Yes\n";
        else{
            int mid=(l+r)>>1;
            Sol(ls(u),l,mid),Sol(rs(u),mid+1,r);
        }
    }while(!st.empty())
        st.top().fr=st.top().se,st.pop();
    return;
}
int main(){
    n=read(),m=read(),k=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        int l=read(),r=read();
        Add_edge(1,1,k,l+1,r,x,y);
    }for(int i=1;i<=2*n;i++)fa[i]=i,sz[i]=1;
    Sol(1,1,k);
    return 0;
}
